using Microsoft.VisualStudio.TestTools.UnitTesting;
using Payments;

namespace Payments.Tests;

[TestClass]
public class PaymentGatewayTests
{
    private PaymentGateway _gateway = null!;

    [TestInitialize]
    public void Setup()
    {
        _gateway = new PaymentGateway();
    }

    #region ChargeAsync Tests

    [TestMethod]
    public async Task ChargeAsync_ValidCardAndAmount_ReturnsSuccessWithChargeId()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 49.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_ZeroAmount_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_NegativeAmount_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", -10.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public async Task ChargeAsync_NullCardToken_ThrowsArgumentNullException()
    {
        await _gateway.ChargeAsync(null!, 25.00m);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task ChargeAsync_EmptyCardToken_ThrowsArgumentException()
    {
        await _gateway.ChargeAsync(string.Empty, 25.00m);
    }

    [TestMethod]
    public async Task ChargeAsync_DeclinedCard_ReturnsFailure()
    {
        var result = await _gateway.ChargeAsync("tok_declined", 50.00m);

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_LargeAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 9999.99m);

        Assert.IsTrue(result.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(result.ChargeId));
    }

    [TestMethod]
    public async Task ChargeAsync_MinimumPositiveAmount_ReturnsSuccess()
    {
        var result = await _gateway.ChargeAsync("tok_valid_visa", 0.01m);

        Assert.IsTrue(result.Success);
    }

    #endregion

    #region RefundAsync Tests

    [TestMethod]
    public async Task RefundAsync_ValidChargeId_ReturnsSuccessWithRefundId()
    {
        var chargeResult = await _gateway.ChargeAsync("tok_valid_visa", 30.00m);
        var refundResult = await _gateway.RefundAsync(chargeResult.ChargeId);

        Assert.IsTrue(refundResult.Success);
        Assert.IsFalse(string.IsNullOrWhiteSpace(refundResult.RefundId));
    }

    [TestMethod]
    public async Task RefundAsync_NonExistentChargeId_ReturnsFailure()
    {
        var result = await _gateway.RefundAsync("ch_nonexistent");

        Assert.IsFalse(result.Success);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentNullException))]
    public async Task RefundAsync_NullChargeId_ThrowsArgumentNullException()
    {
        await _gateway.RefundAsync(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public async Task RefundAsync_EmptyChargeId_ThrowsArgumentException()
    {
        await _gateway.RefundAsync(string.Empty);
    }

    [TestMethod]
    public async Task RefundAsync_AlreadyRefundedCharge_ReturnsFailure()
    {
        var chargeResult = await _gateway.ChargeAsync("tok_valid_visa", 20.00m);
        await _gateway.RefundAsync(chargeResult.ChargeId);

        // Second refund on same charge should fail
        var secondRefund = await _gateway.RefundAsync(chargeResult.ChargeId);

        Assert.IsFalse(secondRefund.Success);
    }

    #endregion

    #region Integration / Workflow Tests

    [TestMethod]
    public async Task ChargeAndRefund_FullWorkflow_BothSucceed()
    {
        var charge = await _gateway.ChargeAsync("tok_valid_visa", 100.00m);
        Assert.IsTrue(charge.Success);

        var refund = await _gateway.RefundAsync(charge.ChargeId);
        Assert.IsTrue(refund.Success);
    }

    [TestMethod]
    public async Task ChargeAsync_MultipleConcurrentCharges_AllReturnUniqueIds()
    {
        var tasks = Enumerable.Range(1, 5)
            .Select(i => _gateway.ChargeAsync("tok_valid_visa", i * 10.00m))
            .ToArray();

        var results = await Task.WhenAll(tasks);

        Assert.IsTrue(results.All(r => r.Success));
        var ids = results.Select(r => r.ChargeId).ToList();
        CollectionAssert.AllItemsAreUnique(ids);
    }

    #endregion
}

